"use client";

import * as React from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { GripVertical, ImageIcon, Trash2, Tv } from "lucide-react";
import { toast } from "sonner";
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DragEndEvent,
} from "@dnd-kit/core";
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  useSortable,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";

import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ContentPicker } from "./content-picker";
import { ChannelPicker } from "./channel-picker";

export interface ContentItem {
  _id: string;
  name: string;
  url: string;
  mime_type: string;
}

export interface Screen {
  _id: string;
  screen_name: string;
  location_name: string;
  assigned_playlist_name?: string;
}

export interface PlaylistData {
  _id: string;
  name: string;
  content: Array<{ type: "content" | "channel"; id: string | null; name: string }>;
}

interface PlaylistItem {
  localKey: string;
  type: "content" | "channel";
  id: string | null;
  name: string;
  url?: string;
  mime_type?: string;
}

interface PlaylistFormProps {
  mode: "create" | "edit";
  playlist?: PlaylistData;
  content: ContentItem[];
  screens: Screen[];
  assignedScreenIds?: string[];
}

export function PlaylistForm({
  mode,
  playlist,
  content,
  screens,
  assignedScreenIds = [],
}: PlaylistFormProps) {
  const router = useRouter();
  const [name, setName] = React.useState(playlist?.name ?? "");
  const [playlistItems, setPlaylistItems] = React.useState<PlaylistItem[]>(
    () =>
      playlist?.content?.map((item) => ({
        localKey: crypto.randomUUID(),
        type: item.type,
        id: item.id,
        name: item.name,
        url: item.type === "content" ? content.find((c) => c._id === item.id)?.url : undefined,
        mime_type:
          item.type === "content"
            ? content.find((c) => c._id === item.id)?.mime_type
            : undefined,
      })) ?? []
  );
  const [selectedScreenIds, setSelectedScreenIds] = React.useState<string[]>(assignedScreenIds);
  const [pickerOpen, setPickerOpen] = React.useState(false);
  const [channelPickerOpen, setChannelPickerOpen] = React.useState(false);
  const [saving, setSaving] = React.useState(false);

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event;
    if (over && active.id !== over.id) {
      setPlaylistItems((items) => {
        const oldIndex = items.findIndex((i) => i.localKey === active.id);
        const newIndex = items.findIndex((i) => i.localKey === over.id);
        return arrayMove(items, oldIndex, newIndex);
      });
    }
  }

  function handleContentAdd(selectedIds: string[]) {
    const newItems = selectedIds
      .filter((id) => !playlistItems.some((p) => p.id === id && p.type === "content"))
      .map((id) => {
        const c = content.find((c) => c._id === id)!;
        return {
          localKey: crypto.randomUUID(),
          type: "content" as const,
          id: c._id,
          name: c.name,
          url: c.url,
          mime_type: c.mime_type,
        };
      });
    setPlaylistItems((prev) => [...prev, ...newItems]);
  }

  function handleChannelAdd(channelNames: string[]) {
    const newItems = channelNames
      .filter((name) => !playlistItems.some((p) => p.type === "channel" && p.name === name))
      .map((name) => ({
        localKey: crypto.randomUUID(),
        type: "channel" as const,
        id: null,
        name,
      }));
    setPlaylistItems((prev) => [...prev, ...newItems]);
  }

  function removeItem(localKey: string) {
    setPlaylistItems((prev) => prev.filter((i) => i.localKey !== localKey));
  }

  function toggleScreen(screenId: string) {
    setSelectedScreenIds((prev) =>
      prev.includes(screenId) ? prev.filter((x) => x !== screenId) : [...prev, screenId]
    );
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!name.trim()) {
      toast.error("Playlist name is required");
      return;
    }

    setSaving(true);
    try {
      const url =
        mode === "create" ? "/api/playlists" : `/api/playlists/${playlist!._id}`;
      const method = mode === "create" ? "POST" : "PATCH";

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: name.trim(),
          content: playlistItems.map(({ type, id, name }) => ({ type, id, name })),
          screen_ids: selectedScreenIds,
        }),
      });

      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.error ?? "Failed to save playlist");
      }

      router.push("/playlists");
    } catch (err) {
      toast.error(err instanceof Error ? err.message : "Something went wrong");
    } finally {
      setSaving(false);
    }
  }

  return (
    <div className="flex flex-col gap-6 pt-4 max-w-2xl">
      <h1 className="text-xl font-semibold">
        {mode === "create" ? "Create Playlist" : "Edit Playlist"}
      </h1>

      <form onSubmit={handleSubmit} className="flex flex-col gap-8">
        {/* Section 1 — Name */}
        <div className="flex flex-col gap-2">
          <Label htmlFor="playlist-name">Name</Label>
          <Input
            id="playlist-name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="My Playlist"
            required
          />
        </div>

        {/* Section 2 — Content */}
        <div className="flex flex-col gap-3">
          <Label>Content</Label>
          <div className="flex items-center gap-2">
            <Button
              type="button"
              variant="outline"
              onClick={() => setPickerOpen(true)}
              className="w-fit"
            >
              Add Content
            </Button>
            <Button
              type="button"
              variant="outline"
              onClick={() => setChannelPickerOpen(true)}
              className="w-fit"
            >
              Add Channel
            </Button>
          </div>

          {playlistItems.length > 0 && (
            <DndContext
              sensors={sensors}
              collisionDetection={closestCenter}
              onDragEnd={handleDragEnd}
            >
              <SortableContext
                items={playlistItems.map((i) => i.localKey)}
                strategy={verticalListSortingStrategy}
              >
                <div className="flex flex-col gap-2">
                  {playlistItems.map((item) => (
                    <SortablePlaylistItem
                      key={item.localKey}
                      item={item}
                      onRemove={() => removeItem(item.localKey)}
                    />
                  ))}
                </div>
              </SortableContext>
            </DndContext>
          )}
        </div>

        {/* Section 3 — Assign to Screens */}
        <div className="flex flex-col gap-3">
          <div>
            <Label>Assign to Screens</Label>
            <p className="text-xs text-muted-foreground mt-0.5">(optional)</p>
          </div>
          {screens.length === 0 ? (
            <p className="text-sm text-muted-foreground">No screens found for this account.</p>
          ) : (
            <div className="flex flex-col gap-2">
              {screens.map((screen) => (
                <div key={screen._id} className="flex items-center gap-2">
                  <Checkbox
                    id={`screen-${screen._id}`}
                    checked={selectedScreenIds.includes(screen._id)}
                    onCheckedChange={() => toggleScreen(screen._id)}
                  />
                  <Label
                    htmlFor={`screen-${screen._id}`}
                    className="font-normal cursor-pointer"
                  >
                    {screen.screen_name}
                    {screen.location_name ? ` — ${screen.location_name}` : ""}
                    {screen.assigned_playlist_name && (
                      <span className="text-muted-foreground ml-1">
                        ({screen.assigned_playlist_name})
                      </span>
                    )}
                  </Label>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Section 4 — Actions */}
        <div className="flex items-center gap-3">
          <Button variant="outline" asChild>
            <Link href="/playlists">Cancel</Link>
          </Button>
          <Button type="submit" disabled={saving}>
            {saving ? "Saving..." : "Save"}
          </Button>
        </div>
      </form>

      <ContentPicker
        content={content}
        alreadySelected={playlistItems.filter((p) => p.type === "content").map((p) => p.id!)}
        onAdd={handleContentAdd}
        open={pickerOpen}
        onOpenChange={setPickerOpen}
      />

      <ChannelPicker
        alreadySelected={playlistItems.filter((p) => p.type === "channel").map((p) => p.name)}
        onAdd={handleChannelAdd}
        open={channelPickerOpen}
        onOpenChange={setChannelPickerOpen}
      />
    </div>
  );
}

interface SortablePlaylistItemProps {
  item: PlaylistItem;
  onRemove: () => void;
}

function SortablePlaylistItem({ item, onRemove }: SortablePlaylistItemProps) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } =
    useSortable({ id: item.localKey });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
  };

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="flex items-center gap-3 p-2 rounded-md border bg-card"
    >
      <button
        type="button"
        {...attributes}
        {...listeners}
        className="cursor-grab text-muted-foreground touch-none"
      >
        <GripVertical className="size-4" />
      </button>

      <div className="w-14 shrink-0 aspect-video relative bg-muted rounded overflow-hidden">
        {item.type === "content" ? (
          <ContentThumbnail url={item.url} mime_type={item.mime_type} name={item.name} />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center">
            <Tv className="size-4 text-muted-foreground" />
          </div>
        )}
      </div>

      <span className="flex-1 text-sm truncate">{item.name}</span>

      <button
        type="button"
        onClick={onRemove}
        className="text-muted-foreground hover:text-destructive transition-colors"
      >
        <Trash2 className="size-4" />
        <span className="sr-only">Remove</span>
      </button>
    </div>
  );
}

interface ContentThumbnailProps {
  url?: string;
  mime_type?: string;
  name: string;
}

function ContentThumbnail({ url, mime_type, name }: ContentThumbnailProps) {
  const isImage = mime_type?.startsWith("image/");
  const isVideo = mime_type?.startsWith("video/");

  if (isImage && url) {
    return (
      <img
        src={url}
        alt={name}
        className="absolute inset-0 h-full w-full object-cover"
      />
    );
  }
  if (isVideo && url) {
    return (
      <video
        src={url}
        className="absolute inset-0 h-full w-full object-cover"
        controls={false}
        autoPlay={false}
        preload="metadata"
        muted
      />
    );
  }
  return (
    <div className="absolute inset-0 flex items-center justify-center">
      <ImageIcon className="size-4 text-muted-foreground" />
    </div>
  );
}
